require_once __DIR__ . '/../includes/library.php';
require_once __DIR__ . '/../includes/revenue_access_governance.php';
sf_revenue_guard_json_write('library',120,900);$userId=sf_current_user_id();if(!$userId)sf_json_response(['ok'=>false,'error'=>'login_required','message'=>'Sign in to save member library items.'],401);$data=sf_request_json();$action=(string)($data['action']??'save');$type=strtolower(trim((string)($data['content_type']??'')));$contentId=sf_int_from_request($data,'content_id');$status=strtolower(trim((string)($data['library_status']??'saved')));$allowed=['video','episode','song','album','product'];if(!array_key_exists($status,sf_library_statuses()))$status='saved';if(!in_array($type,$allowed,true)||$contentId<=0)sf_json_response(['ok'=>false,'error'=>'invalid_catalog_reference'],422);if(!sf_db()||!sf_library_table_exists('member_library_items'))sf_json_response(['ok'=>false,'error'=>'library_table_missing'],503);try{if($action==='remove'){$removed=sf_library_remove_item((int)$userId,$type,$contentId,$status);sf_json_response(['ok'=>$removed,'removed'=>$removed,'content_type'=>$type,'content_id'=>$contentId,'library_status'=>$status]);}if($action!=='save')sf_json_response(['ok'=>false,'error'=>'unknown_action'],400);$item=sf_library_catalog_item($type,$contentId,$status);if(!$item)sf_json_response(['ok'=>false,'error'=>'catalog_item_not_found'],404);$saved=sf_library_save_item((int)$userId,$item);sf_json_response(['ok'=>$saved,'saved'=>$saved,'item'=>$item]);}catch(Throwable$e){error_log('Library API failed: '.$e->getMessage());sf_json_response(['ok'=>false,'error'=>'library_action_failed'],500);}
